@app.delete("/model")
def delete_model() -> Dict[str, Any]:
    if os.path.exists(EMBEDDING_MODEL_PATH):
        os.remove(EMBEDDING_MODEL_PATH)
        return {"success": True, "deleted": True}
    return {"success": True, "deleted": False}


